def _build_map_html(current_value: str = "") -> str:
    """產生彰化縣地圖選擇器的完整 HTML，供 st.components.v1.html 嵌入。"""
    escaped = current_value.replace("'", "\\'").replace("`", "\\`")
    colors = "['#B5D4F4','#9FE1CB','#FAC775','#C0DD97','#F5C4B3','#CECBF6','#F0997B','#85B7EB','#EAF3DE','#FAEEDA','#E1F5EE','#AFA9EC','#5DCAA5']"

    return f"""<!DOCTYPE html><html><head><meta charset="utf-8">
<style>
*{{box-sizing:border-box;margin:0;padding:0}}
body{{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:transparent}}
.bar{{display:flex;align-items:center;gap:8px;padding:8px 12px;margin-bottom:6px;
  background:#f8f9fa;border:1px solid #dee2e6;border-radius:10px}}
.lbl{{font-size:13px;color:#6c757d;white-space:nowrap}}
.val{{font-size:15px;font-weight:500;color:#212529;flex:1}}
.clr{{font-size:12px;color:#6c757d;background:none;border:1px solid #ced4da;
  border-radius:6px;padding:3px 8px;cursor:pointer}}
.clr:hover{{background:#e9ecef}}
.tip{{font-size:11px;color:#adb5bd;margin-bottom:3px}}
.out{{display:flex;align-items:center;justify-content:center;gap:6px;
  padding:8px;margin-top:6px;width:100%;background:white;
  border:1px solid #ced4da;border-radius:8px;cursor:pointer;
  font-size:13px;color:#6c757d;font-family:inherit}}
.out:hover{{background:#f8f9fa}}
.out.sel{{background:#dbeafe;border-color:#3b82f6;color:#1e40af;font-weight:500}}
</style></head><body>
<div class="bar">
  <span class="lbl">居住地區：</span>
  <span class="val" id="d">{current_value if current_value else "（請點選地圖或下方按鈕）"}</span>
  <button class="clr" onclick="clrSel()">清除</button>
</div>
<p class="tip">點選彰化縣地圖上的鄉鎮市以選擇</p>
<svg id="map" viewBox="16 62 370 355" xmlns="http://www.w3.org/2000/svg"
     style="width:100%;display:block;cursor:pointer"></svg>
<button class="out" id="ob" onclick="selOut()">🗺 彰化縣以外</button>
<script>
{_TOWNS_JS}
const C={colors};
const svg=document.getElementById('map');
let cur=null;
const iv='{escaped}';
function send(v){{window.parent.postMessage({{type:'streamlit:setComponentValue',value:v}},'*');}}
TOWNS.forEach((t,i)=>{{
  const p=document.createElementNS('http://www.w3.org/2000/svg','path');
  p.setAttribute('d',t.d);p.setAttribute('fill',C[i%C.length]);
  p.setAttribute('stroke','white');p.setAttribute('stroke-width','0.7');
  p.addEventListener('mouseenter',()=>{{if(p!==cur)p.setAttribute('stroke-width','1.5');}});
  p.addEventListener('mouseleave',()=>{{if(p!==cur)p.setAttribute('stroke-width','0.7');}});
  p.addEventListener('click',()=>selT(p,t.name));
  svg.appendChild(p);
  const tx=document.createElementNS('http://www.w3.org/2000/svg','text');
  tx.setAttribute('x',t.cx);tx.setAttribute('y',t.cy);
  tx.setAttribute('text-anchor','middle');tx.setAttribute('dominant-baseline','middle');
  tx.setAttribute('font-size','7.5');tx.setAttribute('fill','#1e3a5f');
  tx.setAttribute('pointer-events','none');tx.textContent=t.name;
  svg.appendChild(tx);
  if(t.name===iv){{p.setAttribute('stroke','#185FA5');p.setAttribute('stroke-width','2');cur=p;}}
}});
if(iv==='彰化縣以外')document.getElementById('ob').classList.add('sel');
function selT(el,name){{
  if(cur){{cur.setAttribute('stroke','white');cur.setAttribute('stroke-width','0.7');}}
  el.setAttribute('stroke','#185FA5');el.setAttribute('stroke-width','2');cur=el;
  document.getElementById('d').textContent=name;
  document.getElementById('ob').classList.remove('sel');
  send(name);
}}
function selOut(){{
  if(cur){{cur.setAttribute('stroke','white');cur.setAttribute('stroke-width','0.7');cur=null;}}
  document.getElementById('d').textContent='彰化縣以外';
  document.getElementById('ob').classList.add('sel');
  send('彰化縣以外');
}}
function clrSel(){{
  if(cur){{cur.setAttribute('stroke','white');cur.setAttribute('stroke-width','0.7');cur=null;}}
  document.getElementById('d').textContent='（請點選地圖或下方按鈕）';
  document.getElementById('ob').classList.remove('sel');
  send('');
}}
</script></body></html>"""


# ── Google Sheets 儲存 ──────────────────────────────────────────────────────

def save_to_gsheet(data: Dict[str, Any]) -> bool:
    try:
        scopes = [
            "https://www.googleapis.com/auth/spreadsheets",
            "https://www.googleapis.com/auth/drive",
        ]
        creds = Credentials.from_service_account_info(
            st.secrets["gcp_service_account"], scopes=scopes
        )
        client = gspread.authorize(creds)
        spreadsheet_id = "1CRbnOGaIfbXu-ZIeKQMgThN2JT3fT6qWRqaMQamQmMo"
        sheet = client.open_by_key(spreadsheet_id).get_worksheet(0)
        if not sheet.get_all_values():
            sheet.append_row(list(data.keys()))
        sheet.append_row(list(data.values()))
        return True
    except Exception as e:
        logger.error(f"雲端儲存失敗: {str(e)}")
        return False


