# ── 必填驗證 ───────────────────────────────────────────────────────────────

def build_required_error_list(
    township, age, identity_role, industry_type, q1, q2, q3, q4, q5
) -> list[str]:
    errors = []
    if not township or not township.strip():
        errors.append("「居住地區」尚未選擇")
    if age == "請選擇":
        errors.append("「年齡層」尚未選擇")
    if identity_role is None:
        errors.append("「主要身分」尚未選擇")
    if industry_type is None:
        errors.append("「從業類別」尚未選擇")
    for label, val in [("資訊易讀性", q1), ("意識提升", q2), ("環境友善", q3),
                       ("參與便利", q4), ("整體滿意度", q5)]:
        if val is None:
            errors.append(f"「{label}」尚未選擇")
    return errors


# ── 主程式 ─────────────────────────────────────────────────────────────────

def main() -> None:
    st.set_page_config(page_title="Climate-Action-Feedback", page_icon="🌍", layout="centered")
    inject_custom_css()

    # session state 初始化
    if "township" not in st.session_state:
        st.session_state["township"] = ""

    st.title("氣候變遷公眾參與活動問卷")
    st.caption("彰化縣環境保護局感謝您的參與")

    with st.container():
        st.markdown('<div id="basic-info-section"></div>', unsafe_allow_html=True)
        st.subheader("一、基本資料統計")

        c1, c2 = st.columns(2)
        with c1:
            gender = st.radio("您的性別：", ["男", "女", "其他／不想透露"], horizontal=True, index=None)
            age = st.selectbox("您的年齡層：",
                               ["請選擇", "18 歲以下", "19-35 歲", "36-50 歲", "51-64 歲", "65 歲以上"])
        with c2:
            # ── 地圖選擇器 ──
            st.markdown("**居住地區（彰化縣）：**")
            map_html = _build_map_html(st.session_state["township"])
            result = components.html(map_html, height=480, scrolling=False)
            # postMessage 回傳值會存在 result；若非 None 則更新 session_state
            if result is not None:
                st.session_state["township"] = result

            is_first = st.radio("首次參加此類活動？", ["是", "否"], horizontal=True, index=None)

        st.divider()

        identity_role = st.radio(
            "您的主要身分（社會角色）：",
            ["一般民眾（非社區幹部或志工身分）", "村里鄰長／社區幹部／志工", "其他"],
            index=None,
        )
        other_role_text = ""
        if identity_role == "其他":
            other_role_text = st.text_input("請說明身分（選填）：", key="role_other",
                                            placeholder="請輸入您的身分說明")

        industry_type = st.radio(
            "您的從業類別：",
            ["軍公教", "農林漁牧業", "工／商／服務業", "家庭管理／退休", "學生", "其他"],
            index=None, horizontal=True,
        )
        other_industry_text = ""
        if industry_type == "其他":
            other_industry_text = st.text_input("請說明行業（選填）：", key="ind_other",
                                                placeholder="請輸入您的行業類別")

        specific_group = st.selectbox(
            "特定族群屬性（選填，僅供去識別化統計使用）：",
            ["無", "新住民", "原住民", "其他特定族群"], index=0,
        )
        other_group_text = ""
        if specific_group == "其他特定族群":
            other_group_text = st.text_input("請說明特定族群身分（選填）：", key="group_other",
                                             placeholder="請輸入您的族群屬性說明")

        st.divider()
        st.subheader("二、活動感受與友善評估")
        st.caption("請點選分數：1=非常不同意，2=不同意，3=普通，4=同意，5=非常同意")

        score_options = [1, 2, 3, 4, 5]
        q1 = st.radio("1. 資訊易讀性（簡單易懂）", score_options, index=None, horizontal=True,
                      format_func=lambda x: f"{x}分")
        q2 = st.radio("2. 意識提升（了解氣候對生活影響）", score_options, index=None, horizontal=True,
                      format_func=lambda x: f"{x}分")
        q3 = st.radio("3. 環境友善（場地安全便利）", score_options, index=None, horizontal=True,
                      format_func=lambda x: f"{x}分")
        q4 = st.radio("4. 參與便利（時段符合家庭工作）", score_options, index=None, horizontal=True,
                      format_func=lambda x: f"{x}分")
        q5 = st.radio("5. 整體滿意度（必填）", score_options, index=None, horizontal=True,
                      format_func=lambda x: f"{x}分")
        st.info(f"目前整體滿意度分數：{f'{q5}/5' if q5 is not None else '尚未選擇'}")

        st.divider()
        st.subheader("三、開放性建議")
        gain = st.text_area("最有印象或收穫最多的內容：", placeholder="請自由填寫")
        need = st.text_area("參與不便之處（例如：交通、照顧需求）：", placeholder="請自由填寫")

        if st.button("提交問卷", type="primary", use_container_width=True):
            township_val = st.session_state.get("township", "")
            errors = build_required_error_list(
                township_val, age, identity_role, industry_type, q1, q2, q3, q4, q5
            )
            if errors:
                for err in errors:
                    st.error(err)
                st.markdown("👉 [前往補充填寫資料](#basic-info-section)")
                return

            final_role = (f"其他 ({other_role_text.strip()})"
                          if identity_role == "其他" and other_role_text.strip()
                          else identity_role)
            final_industry = (f"其他 ({other_industry_text.strip()})"
                              if industry_type == "其他" and other_industry_text.strip()
                              else industry_type)
            final_group = (f"其他 ({other_group_text.strip()})"
                           if specific_group == "其他特定族群" and other_group_text.strip()
                           else (specific_group if specific_group != "無" else ""))

            record = {
                "時間戳記": datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "性別": gender,
                "年齡": age,
                "行政區": township_val.strip(),
                "首次參加": is_first,
                "社會角色": final_role,
                "從業類別": final_industry,
                "族群屬性": final_group,
                "Q1資訊易讀": q1,
                "Q2意識提升": q2,
                "Q3環境友善": q3,
                "Q4參與便利": q4,
                "Q5整體滿意": q5,
                "正面獲益": gain.strip(),
                "改善建議": need.strip(),
            }

            with st.spinner("正在同步至雲端資料庫..."):
                if save_to_gsheet(record):
                    st.success("提交成功，資料已完成去識別化儲存。")
                    st.session_state["township"] = ""
                    st.balloons()
                else:
                    st.error("上傳失敗，請確認網路連線或系統 Secrets 設定。")


if __name__ == "__main__":
    main()
